class DeviceState:
    def __init__(self):
        self.led = machine.Pin(2, machine.Pin.OUT)
        self.relay = None
        try:
            self.relay = machine.Pin(4, machine.Pin.OUT)
        except Exception:
            pass
        self.state = {
            "led": False,
            "relay": False,
            "brightness": 0,
            "temperature": 0.0,
            "uptime": 0,
        }

    def update_uptime(self):
        self.state["uptime"] = time.ticks_ms() // 1000

    def turn_on(self, target="led"):
        if target == "led":
            self.led.value(1)
            self.state["led"] = True
        elif target == "relay" and self.relay:
            self.relay.value(1)
            self.state["relay"] = True
        return self.get_status()

    def turn_off(self, target="led"):
        if target == "led":
            self.led.value(0)
            self.state["led"] = False
        elif target == "relay" and self.relay:
            self.relay.value(0)
            self.state["relay"] = False
        return self.get_status()

    def toggle(self, target="led"):
        if target == "led":
            current = self.led.value()
            self.led.value(1 - current)
            self.state["led"] = bool(1 - current)
        elif target == "relay" and self.relay:
            current = self.relay.value()
            self.relay.value(1 - current)
            self.state["relay"] = bool(1 - current)
        return self.get_status()

    def set_brightness(self, value):
        value = max(0, min(100, int(value)))
        self.state["brightness"] = value
        return self.get_status()

    def get_status(self):
        self.update_uptime()
        return {"status": "ok", "state": self.state.copy()}


