def is_local_ip(addr):
    """Check if an IP address is on a local/private network."""
    if not addr:
        return False
    ip = addr[0] if isinstance(addr, tuple) else addr
    parts = ip.split(".")
    if len(parts) != 4:
        return False
    try:
        octets = [int(p) for p in parts]
    except ValueError:
        return False
    # 10.x.x.x
    if octets[0] == 10:
        return True
    # 172.16.x.x - 172.31.x.x
    if octets[0] == 172 and 16 <= octets[1] <= 31:
        return True
    # 192.168.x.x
    if octets[0] == 192 and octets[1] == 168:
        return True
    # 127.x.x.x
    if octets[0] == 127:
        return True
    return False


def validate_origin(origin, client_addr):
    """Validate the Origin header to prevent cross-origin attacks."""
    if not origin:
        # No origin header - could be non-browser client; allow if local
        return is_local_ip(client_addr)

    # Only allow http origins (not ws:// or wss:// which browsers don't send)
    if not origin.startswith("http://") and not origin.startswith("https://"):
        return False

    # Extract host from origin
    try:
        host_part = origin.split("://", 1)[1]
        host = host_part.split(":")[0].split("/")[0]
    except (IndexError, ValueError):
        return False

    # Check if origin is from a local IP
    if not is_local_ip((host,)):
        # Allow localhost
        if host not in ("localhost",):
            return False

    # If ALLOWED_ORIGINS is set, check against whitelist
    if ALLOWED_ORIGINS is not None:
        if origin not in ALLOWED_ORIGINS:
            return False

    return True


def sanitize_json_string(s, max_len=1024):
    """Sanitize a string to prevent injection attacks."""
    if not isinstance(s, str):
        return ""
    return s[:max_len]


def rate_limit_check(client_info):
    """Simple rate limiting per client."""
    now = time.ticks_ms()
    if "msg_timestamps" not in client_info:
        client_info["msg_timestamps"] = []

    # Remove timestamps older than 1 second
    client_info["msg_timestamps"] = [
        t for t in client_info["msg_timestamps"]
        if time.ticks_diff(now, t) < 1000
    ]

    if len(client_info["msg_timestamps"]) >= 20:  # Max 20 messages per second
        return False

    client_info["msg_timestamps"].append(now)
    return True


