OPCODE_CONT = 0x0
OPCODE_TEXT = 0x1
OPCODE_BIN = 0x2
OPCODE_CLOSE = 0x8
OPCODE_PING = 0x9
OPCODE_PONG = 0xA

WS_MAGIC = b"258EAFA5-E914-47DA-95CA-5AB5AA98"


def compute_accept_key(key):
    """Compute the Sec-WebSocket-Accept value."""
    combined = key.encode("utf-8") + b"258EAFA5-E914-47DA-95CA-5AB5AA98"
    sha1_hash = hashlib.sha1(combined).digest()
    return binascii.b2a_base64(sha1_hash).strip().decode("utf-8")


def parse_http_headers(data):
    """Parse HTTP request headers from raw bytes."""
    headers = {}
    method = ""
    path = ""
    try:
        text = data.decode("utf-8")
        lines = text.split("\r\n")
        if lines:
            request_line = lines[0].split(" ")
            if len(request_line) >= 2:
                method = request_line[0]
                path = request_line[1]
        for line in lines[1:]:
            if ":" in line:
                key, value = line.split(":", 1)
                headers[key.strip().lower()] = value.strip()
    except Exception:
        pass
    return method, path, headers


def do_websocket_handshake(client_sock, client_addr):
    """Perform the WebSocket handshake with security checks."""
    try:
        client_sock.settimeout(5)
        data = client_sock.recv(2048)
        if not data:
            return False, "No data received"

        method, path, headers = parse_http_headers(data)

        # Validate HTTP method
        if method != "GET":
            send_http_error(client_sock, 405, "Method Not Allowed")
            return False, "Invalid method"

        # Validate path
        if path not in ("/ws", "/", "/websocket"):
            send_http_error(client_sock, 404, "Not Found")
            return False, "Invalid path"

        # Check required WebSocket headers
        upgrade = headers.get("upgrade", "").lower()
        connection = headers.get("connection", "").lower()
        ws_key = headers.get("sec-websocket-key", "")
        ws_version = headers.get("sec-websocket-version", "")

        if upgrade != "websocket":
            send_http_error(client_sock, 400, "Bad Request - Not a WebSocket request")
            return False, "Not a WebSocket upgrade"

        if "upgrade" not in connection:
            send_http_error(client_sock, 400, "Bad Request - Missing Connection: Upgrade")
            return False, "Missing Connection upgrade"

        if not ws_key:
            send_http_error(client_sock, 400, "Bad Request - Missing WebSocket key")
            return False, "Missing WS key"

        if ws_version != "13":
            send_http_error(client_sock, 426, "Upgrade Required",
                            extra_headers="Sec-WebSocket-Version: 13\r\n")
            return False, "Unsupported WS version"

        # Validate Origin
        origin = headers.get("origin", "")
        if not validate_origin(origin, client_addr):
            send_http_error(client_sock, 403, "Forbidden - Origin not allowed")
            return False, "Origin rejected: {}".format(origin)

        # Reject if not from local network
        if not is_local_ip(client_addr):
            send_http_error(client_sock, 403, "Forbidden - External access denied")
            return False, "External IP rejected"

        # Compute accept key
        accept_key = compute_accept_key(ws_key)

        # Send handshake response
        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            "Sec-WebSocket-Accept: {}\r\n"
            "X-Content-Type-Options: nosniff\r\n"
            "X-Frame-Options: DENY\r\n"
            "\r\n"
        ).format(accept_key)

        client_sock.send(response.encode("utf-8"))
        client_sock.settimeout(None)
        return True, "OK"

    except OSError as e:
        return False, "OSError: {}".format(e)
    except Exception as e:
        return False, "Error: {}".format(e)


def send_http_error(sock, code, message, extra_headers=""):
    """Send an HTTP error response."""
    body = '{{"error":"{}"}}'.format(message)
    response = (
        "HTTP/1.1 {} {}\r\n"
        "Content-Type: application/json\r\n"
        "Content-Length: {}\r\n"
        "Connection: close\r\n"
        "{}"
        "\r\n"
        "{}"
    ).format(code, message, len(body), extra_headers, body)
    try:
        sock.send(response.encode("utf-8"))
    except Exception:
        pass


def read_ws_frame(sock):
    """Read and decode a WebSocket frame. Returns (opcode, payload) or (None, None)."""
    try:
        header = sock.recv(2)
        if not header or len(header) < 2:
            return None, None

        fin = (header[0] >> 7) & 1
        opcode = header[0] & 0x0F
        masked = (header[1] >> 7) & 1
        payload_len = header[1] & 0x7F

        # Clients MUST mask frames
        if not masked:
            return OPCODE_CLOSE, b"Protocol error: unmasked frame"

        if payload_len == 126:
            ext = sock.recv(2)
            if len(ext) < 2:
                return None, None
            payload_len = struct.unpack("!H", ext)[0]
        elif payload_len == 127:
            ext = sock.recv(8)
            if len(ext) < 8:
                return None, None
            payload_len = struct.unpack("!Q", ext)[0]

        # Enforce max frame size
        if payload_len > MAX_FRAME_SIZE:
            return OPCODE_CLOSE, b"Frame too large"

        mask_key = sock.recv(4)
        if len(mask_key) < 4:
            return None, None

        # Read payload in chunks
        payload = b""
        remaining = payload_len
        while remaining > 0:
            chunk_size = min(remaining, 1024)
            chunk = sock.recv(chunk_size)
            if not chunk:
                return None, None
            payload += chunk
            remaining -= len(chunk)

        # Unmask
        unmasked = bytearray(payload)
        for i in range(len(unmasked)):
            unmasked[i] ^= mask_key[i % 4]

        return opcode, bytes(unmasked)

    except OSError:
        return None, None
    except Exception:
        return None, None


def send_ws_frame(sock, data, opcode=OPCODE_TEXT):
    """Send a WebSocket frame (server frames are NOT masked)."""
    try:
        if isinstance(data, str):
            data = data.encode("utf-8")

        frame = bytearray()
        frame.append(0x80 | opcode)  # FIN + opcode

        length = len(data)
        if length < 126:
            frame.append(length)
        elif length < 65536:
            frame.append(126)
            frame.extend(struct.pack("!H", length))
        else:
            frame.append(127)
            frame.extend(struct.pack("!Q", length))

        frame.extend(data)
        sock.send(bytes(frame))
        return True
    except Exception:
        return False


def send_ws_close(sock, code=1000, reason=""):
    """Send a WebSocket close frame."""
    try:
        payload = struct.pack("!H", code) + reason.encode("utf-8")[:123]
        send_ws_frame(sock, payload, OPCODE_CLOSE)
    except Exception:
        pass


