# Command Handler
# ============================================================
VALID_ACTIONS = {
    "turn_on", "turn_off", "toggle", "status",
    "set_brightness", "ping", "auth"
}

VALID_TARGETS = {"led", "relay"}


def handle_command(data, client_info):
    """Parse and handle a JSON command. Returns a JSON response string."""
    try:
        # Sanitize input length
        if len(data) > 1024:
            return json.dumps({"error": "Message too large"})

        cmd = json.loads(data)

        if not isinstance(cmd, dict):
            return json.dumps({"error": "Invalid command format"})

        action = cmd.get("action", "")
        if not isinstance(action, str):
            return json.dumps({"error": "Invalid action type"})

        action = sanitize_json_string(action, 64).strip().lower()

        # Validate action
        if action not in VALID_ACTIONS:
            return json.dumps({
                "error": "Unknown action",
                "valid_actions": list(VALID_ACTIONS)
            })

        # Handle authentication
        if action == "auth":
            token = cmd.get("token", "")
            if not isinstance(token, str):
                return json.dumps({"error": "Invalid token"})
            # Constant-time comparison to prevent timing attacks
            token = sanitize_json_string(token, 256)
            if len(token) == len(AUTH_TOKEN) and _constant_time_compare(token, AUTH_TOKEN):
                client_info["authenticated"] = True
                return json.dumps({"status": "ok", "message": "Authenticated"})
            else:
                client_info["auth_failures"] = client_info.get("auth_failures", 0) + 1
                if client_info["auth_failures"] >= 5:
                    return json.dumps({"error": "Too many auth failures", "disconnect": True})
                return json.dumps({"error": "Authentication failed"})

        # Check authentication for non-auth actions
        if not client_info.get("authenticated", False):
            return json.dumps({"error": "Not authenticated. Send {\"action\":\"auth\",\"token\":\"...\"} first"})

        # Handle ping
        if action == "ping":
            return json.dumps({"status": "ok", "action": "pong", "time": time.ticks_ms()})

        # Handle status
        if action == "status":
            return json.dumps(device.get_status())

        # Get target for device actions
        target = cmd.get("target", "led")
        if not isinstance(target, str):
            target = "led"
        target = sanitize_json_string(target, 32).strip().lower()
        if target not in VALID_TARGETS:
            return json.dumps({"error": "Invalid target", "valid_targets": list(VALID_TARGETS)})

        # Execute device actions
        if action == "turn_on":
            result = device.turn_on(target)
            result["action"] = "turn_on"
            result["target"] = target
            return json.dumps(result)

        elif action == "turn_off":
            result = device.turn_off(target)
            result["action"] = "turn_off"
            result["target"] = target
            return json.dumps(result)

        elif action == "toggle":
            result = device.toggle(target)
            result["action"] = "toggle"
            result["target"] = target
            return json.dumps(result)

        elif action == "set_brightness":
            value = cmd.get("value", 0)
            if not isinstance(value, (int, float)):
                return json.dumps({"error": "Invalid brightness value"})
            result = device.set_brightness(value)
            result["action"] = "set_brightness"
            return json.dumps(result)

        return json.dumps({"error": "Unhandled action"})

    except ValueError:
        return json.dumps({"error": "Invalid JSON"})
    except Exception as e:
        return json.dumps({"error": "Internal error"})


def _constant_time_compare(a, b):
    """Constant-time string comparison to prevent timing attacks."""
    if len(a) != len(b):
        return False
    result = 0
    for x, y in zip(a, b):
        result |= ord(x) ^ ord(y)
    return result == 0


