def connect_wifi():
    """Connect to WiFi and return the IP address."""
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)

    if not wlan.isconnected():
        print("[WiFi] Connecting to {}...".format(WIFI_SSID))
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)

        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print("[WiFi] Waiting... ({})".format(timeout))

    if wlan.isconnected():
        config = wlan.ifconfig()
        print("[WiFi] Connected! IP: {}".format(config[0]))
        return config[0]
    else:
        print("[WiFi] Connection failed!")
        return None


