class WebSocketServer:
    def __init__(self, host, port):
        self.host = host
        self.port = port
        self.server_sock = None
        self.clients = {}  # sock -> client_info
        self.running = False

    def start(self):
        """Start the WebSocket server."""
        self.server_sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_sock.bind((self.host, self.port))
        self.server_sock.listen(MAX_CLIENTS)
        self.server_sock.setblocking(False)
        self.running = True
        print("[WS] Server started on ws://{}:{}".format(self.host, self.port))
        print("[WS] Accepting connections from local network only")
        print("[WS] Authentication required with token")

    def stop(self):
        """Stop the server and close all connections."""
        self.running = False
        for sock in list(self.clients.keys()):
            self._close_client(sock, 1001, "Server shutting down")
        if self.server_sock:
            self.server_sock.close()
        print("[WS] Server stopped")

    def _close_client(self, sock, code=1000, reason=""):
        """Close a client connection."""
        try:
            send_ws_close(sock, code, reason)
        except Exception:
            pass
        try:
            sock.close()
        except Exception:
            pass
        if sock in self.clients:
            addr = self.clients[sock].get("addr", "unknown")
            print("[WS] Client disconnected: {}".format(addr))
            del self.clients[sock]

    def _accept_new_client(self):
        """Accept a new client connection."""
        try:
            client_sock, client_addr = self.server_sock.accept()
        except OSError:
            return

        print("[WS] New connection from {}:{}".format(client_addr[0], client_addr[1]))

        # Check if from local network
        if not is_local_ip(client_addr):
            print("[WS] Rejected external connection from {}".format(client_addr[0]))
            send_http_error(client_sock, 403, "Forbidden")
            client_sock.close()
            return

        # Check max clients
        if len(self.clients) >= MAX_CLIENTS:
            print("[WS] Max clients reached, rejecting")
            send_http_error(client_sock, 503, "Service Unavailable")
            client_sock.close()
            return

        # Perform WebSocket handshake
        success, msg = do_websocket_handshake(client_sock, client_addr)
        if not success:
            print("[WS] Handshake failed: {}".format(msg))
            client_sock.close()
            return

        # Register client
        client_sock.setblocking(False)
        self.clients[client_sock] = {
            "addr": "{}:{}".format(client_addr[0], client_addr[1]),
            "ip": client_addr[0],
            "connected_at": time.ticks_ms(),
            "last_activity": time.ticks_ms(),
            "authenticated": False,
            "auth_failures": 0,
            "msg_timestamps": [],
        }

        print("[WS] Client connected: {}:{} (total: {})".format(
            client_addr[0], client_addr[1], len(self.clients)))

        # Send welcome message (no sensitive info before auth)
        welcome = json.dumps({
            "type": "welcome",
            "message": "Connected to ESP32 IoT Controller",
            "auth_required": True,
        })
        send_ws_frame(client_sock, welcome)

    def _handle_client_data(self, sock):
        """Handle incoming data from a client."""
        client_info = self.clients.get(sock)
        if not client_info:
            return

        opcode, payload = read_ws_frame(sock)

        if opcode is None:
            self._close_client(sock, 1006, "Connection lost")
            return

        # Update last activity
        client_info["last_activity"] = time.ticks_ms()

        # Rate limiting
        if not rate_limit_check(client_info):
            response = json.dumps({"error": "Rate limit exceeded"})
            send_ws_frame(sock, response)
            return

        if opcode == OPCODE_TEXT:
            try:
                data = payload.decode("utf-8")
            except UnicodeError:
                send_ws_frame(sock, json.dumps({"error": "Invalid UTF-8"}))
                return

            response = handle_command(data, client_info)

            # Check if we should disconnect (e.g., too many auth failures)
            try:
                resp_obj = json.loads(response)
                if resp_obj.get("disconnect"):
                    send_ws_frame(sock, response)
                    self._close_client(sock, 1008, "Policy violation")
                    return
            except Exception:
                pass

            send_ws_frame(sock, response)

            # Broadcast state changes to all authenticated clients
            try:
                resp_obj = json.loads(response)
                if resp_obj.get("status") == "ok" and "state" in resp_obj:
                    self._broadcast_state(sock, resp_obj)
            except Exception:
                pass

        elif opcode == OPCODE_PING:
            send_ws_frame(sock, payload, OPCODE_PONG)

        elif opcode == OPCODE_PONG:
            client_info["last_pong"] = time.ticks_ms()

        elif opcode == OPCODE_CLOSE:
            self._close_client(sock, 1000, "Client closed")

        elif opcode == OPCODE_BIN:
            # We don't accept binary frames
            send_ws_frame(sock, json.dumps({"error": "Binary frames not supported"}))

    def _broadcast_state(self, sender_sock, state_msg):
        """Broadcast state update to all authenticated clients except sender."""
        broadcast = json.dumps({
            "type": "state_update",
            "state": state_msg.get("state", {}),
        })
        for sock, info in list(self.clients.items()):
            if sock != sender_sock and info.get("authenticated", False):
                try:
                    send_ws_frame(sock, broadcast)
                except Exception:
                    self._close_client(sock, 1006, "Send failed")

    def _check_timeouts(self):
        """Check for client timeouts and send pings."""
        now = time.ticks_ms()
        for sock, info in list(self.clients.items()):
            last_activity = info.get("last_activity", now)
            elapsed = time.ticks_diff(now, last_activity)

            # Connection timeout
            if elapsed > CONNECTION_TIMEOUT * 1000:
                print("[WS] Client timeout: {}".format(info.get("addr")))
                self._close_client(sock, 1001, "Timeout")
                continue

            # Send ping if needed
            last_ping = info.get("last_ping", 0)
            if time.ticks_diff(now, last_ping) > PING_INTERVAL * 1000:
                try:
                    send_ws_frame(sock, b"ping", OPCODE_PING)
                    info["last_ping"] = now
                except Exception:
                    self._close_client(sock, 1006, "Ping failed")

            # Auth timeout - disconnect if not authenticated within 10 seconds
            if not info.get("authenticated", False):
                connected_at = info.get("connected_at", now)
                if time.ticks_diff(now, connected_at) > 10000:
                    print("[WS] Auth timeout: {}".format(info.get("addr")))
                    send_ws_frame(sock, json.dumps({"error": "Authentication timeout"}))
                    self._close_client(sock, 1008, "Auth timeout")

    def run_forever(self):
        """Main server loop."""
        self.start()
        last_timeout_check = time.ticks_ms()
        last_gc = time.ticks_ms()

        try:
            while self.running:
                # Accept new connections
                self._accept_new_client()

                # Handle client data
                for sock in list(self.clients.keys()):
                    try:
                        self._handle_client_data(sock)
                    except OSError as e:
                        # EAGAIN means no data available (non-blocking)
                        if e.args[0] != 11:  # EAGAIN
                            self._close_client(sock, 1006, "Error")
                    except Exception as e:
                        print("[WS] Error handling client: {}".format(e))
                        self._close_client(sock, 1011, "Internal error")

                # Periodic timeout check
                now = time.ticks_ms()
                if time.ticks_diff(now, last_timeout_check) > 5000:
                    self._check_timeouts()
                    last_timeout_check = now

                # Periodic garbage collection
                if time.ticks_diff(now, last_gc) > 30000:
                    import gc
                    gc.collect()
                    last_gc = now

                # Small delay to prevent busy-waiting
                time.sleep_ms(10)

        except KeyboardInterrupt:
            print("\n[WS] Interrupted by user")
        finally:
            self.stop()


