def serve_test_page(ip_addr):
    """Serve a simple test HTML page on port 80."""
    html = """<!DOCTYPE html>
<html>
<head>
<title>ESP32 IoT Control</title>
<meta name="viewport" content="width=device-width, initial-scale=1">
<style>
body {{ font-family: Arial; max-width: 600px; margin: 0 auto; padding: 20px; background: #1a1a2e; color: #eee; }}
h1 {{ color: #0f3460; text-align: center; color: #e94560; }}
.btn {{ padding: 15px 30px; margin: 5px; border: none; border-radius: 8px; cursor: pointer; font-size: 16px; color: white; }}
.on {{ background: #16c79a; }}
.off {{ background: #e94560; }}
.toggle {{ background: #0f3460; }}
.status {{ background: #16213e; padding: 15px; border-radius: 8px; margin: 10px 0; }}
#log {{ background: #0f3460; padding: 10px; border-radius: 8px; height: 200px; overflow-y: auto; font-family: monospace; font-size: 12px; }}
input {{ padding: 10px; margin: 5px; border-radius: 5px; border: 1px solid #333; background: #16213e; color: #eee; }}
.controls {{ text-align: center; }}
</style>
</head>
<body>
<h1>ESP32 IoT Control</h1>
<div class="status">
<p>Connection: <span id="conn">Disconnected</span></p>
<p>Auth: <span id="auth">Not authenticated</span></p>
<p>LED: <span id="led">Unknown</span> | Relay: <span id="relay">Unknown</span></p>
</div>
<div class="controls">
<input type="text" id="token" placeholder="Auth Token" value="">
<button class="btn toggle" onclick="authenticate()">Authenticate</button><br>
<button class="btn on" onclick="send('turn_on','led')">LED ON</button>
<button class="btn off" onclick="send('turn_off','led')">LED OFF</button>
<button class="btn toggle" onclick="send('toggle','led')">Toggle LED</button><br>
<button class="btn on" onclick="send('turn_on','relay')">Relay ON</button>
<button class="btn off" onclick="send('turn_off','relay')">Relay OFF</button><br>
<button class="btn toggle" onclick="send('status')">Status</button>
</div>
<h3>Log</h3>
<div id="log"></div>
<script>
var ws;
function connect() {{
    ws = new WebSocket('ws://{ip}:{port}/ws');
    ws.onopen = function() {{
        document.getElementById('conn').textContent = 'Connected';
        document.getElementById('conn').style.color = '#16c79a';
        log('Connected to server');
    }};
    ws.onmessage = function(e) {{
        log('< ' + e.data);
        try {{
            var d = JSON.parse(e.data);
            if (d.state) {{
                document.getElementById('led').textContent = d.state.led ? 'ON' : 'OFF';
                document.getElementById('relay').textContent = d.state.relay ? 'ON' : 'OFF';
            }}
            if (d.message === 'Authenticated') {{
                document.getElementById('auth').textContent = 'Authenticated';
                document.getElementById('auth').style.color = '#16c79a';
            }}
        }} catch(ex) {{}}
    }};
    ws.onclose = function() {{
        document.getElementById('conn').textContent = 'Disconnected';
        document.getElementById('conn').style.color = '#e94560';
        log('Disconnected. Reconnecting in 3s...');
        setTimeout(connect, 3000);
    }};
    ws.onerror = function() {{ log('Error'); }};
}}
function send(action, target) {{
    if (!ws || ws.readyState !== 1) {{ log('Not connected'); return; }}
    var cmd = {{action: action}};
    if (target) cmd.target = target;
    var msg = JSON.stringify(cmd);
    log('> ' + msg);
    ws.send(msg);
}}
function authenticate() {{
    if (!ws || ws.readyState !== 1) {{ log('Not connected'); return; }}
    var token = document.getElementById('token').value;
    var msg = JSON.stringify({{action: 'auth', token: token}});
    log('> [auth]');
    ws.send(msg);
}}
function log(msg) {{
    var el = document.getElementById('log');
    el.innerHTML += new Date().toLocaleTimeString() + ' ' + msg + '<br>';
    el.scrollTop = el.scrollHeight;
}}
connect();
</script>
</body>
</html>""".format(ip=ip_addr, port=WS_PORT)

    http_sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    http_sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    http_sock.bind(("0.0.0.0", 80))
    http_sock.listen(2)
    http_sock.setblocking(False)
    print("[HTTP] Test page available at http://{}".format(ip_addr))
    return http_sock, html


def handle_http_request(http_sock, html):
    """Handle HTTP requests for the test page."""
    try:
        client, addr = http_sock.accept()
        if not is_local_ip(addr):
            client.close()
            return
        client.settimeout(3)
        request = client.recv(1024)
        response = (
            "HTTP/1.1 200 OK\r\n"
            "Content-Type: text/html; charset=utf-8\r\n"
            "Content-Length: {}\r\n"
            "X-Content-Type-Options: nosniff\r\n"
            "X-Frame-Options: DENY\r\n"
            "Content-Security-Policy: default-src 'self' 'unsafe-inline' ws:;\r\n"
            "Connection: close\r\n"
            "\r\n"
            "{}"
        ).format(len(html), html)
        client.send(response.encode("utf-8"))
        client.close()
    except OSError:
        pass


# ============================================================
# Main Entry Point
# ============================================================
def main():
    # Connect to WiFi
    ip = connect_wifi()
    if not ip:
        print("[Main] Cannot start without WiFi. Resetting in 10s...")
        time.sleep(10)
        machine.reset()

    # Start HTTP test page server
    http_sock, html = serve_test_page(ip)

    # Start WebSocket server
    server = WebSocketServer("0.0.0.0", WS_PORT)

    print("[Main] ==========================================")
    print("[Main] ESP32 IoT WebSocket Server")
    print("[Main] WS: ws://{}:{}".format(ip, WS_PORT))
    print("[Main] HTTP: http://{}".format(ip))
    print("[Main] Auth token required for device control")
    print("[Main] Local network access only")
    print("[Main] ==========================================")

    server.start()
    last_timeout_check = time.ticks_ms()
    last_gc = time.ticks_ms()

    try:
        while server.running:
            # Accept new WebSocket connections
            server._accept_new_client()

            # Handle WebSocket client data
            for sock in list(server.clients.keys()):
                try:
                    server._handle_client_data(sock)
                except OSError as e:
                    if e.args[0] != 11:  # EAGAIN
                        server._close_client(sock, 1006, "Error")
                except Exception:
                    server._close_client(sock, 1011, "Internal error")

            # Handle HTTP requests
            handle_http_request(http_sock, html)

            # Periodic checks
            now = time.ticks_ms()
            if time.ticks_diff(now, last_timeout_check) > 5000:
                server._check_timeouts()
                last_timeout_check = now

            if time.ticks_diff(now, last_gc) > 30000:
                import gc
                gc.collect()
                last_gc = now

            time.sleep_ms(10)

    except KeyboardInterrupt:
        print("\n[Main] Shutting down...")
    finally:
        server.stop()
        http_sock.close()
        print("[Main] Goodbye!")


if __name__ == "__main__":
    main()